import 'prosekit/lit/autocomplete'

import { html, LitElement } from 'lit'

class SlashMenuEmptyElement extends LitElement {
  override createRenderRoot() {
    return this
  }

  override render() {
    return html`
      <prosekit-autocomplete-empty class="relative flex items-center justify-between min-w-32 scroll-my-1 rounded-sm px-3 py-1.5 box-border cursor-default select-none whitespace-nowrap outline-hidden data-highlighted:bg-gray-100 dark:data-highlighted:bg-gray-800">
        <span>No results</span>
      </prosekit-autocomplete-empty>
    `
  }
}

customElements.define('lit-editor-slash-menu-empty', SlashMenuEmptyElement)

import 'prosekit/lit/autocomplete'

import { html, LitElement } from 'lit'

class SlashMenuItemElement extends LitElement {
  static override properties = {
    label: { type: String },
    kbd: { type: String },
  }

  label: string
  kbd: string

  constructor() {
    super()
    this.label = ''
    this.kbd = ''
  }

  override createRenderRoot() {
    return this
  }

  // TODO: maybe this should changed to valueChange event??
  handleSelect = () => {
    this.dispatchEvent(new CustomEvent('select'))
  }

  override render() {
    return html`<prosekit-autocomplete-item
      @select=${this.handleSelect}
      class="relative flex items-center justify-between min-w-32 scroll-my-1 rounded-sm px-3 py-1.5 box-border cursor-default select-none whitespace-nowrap outline-hidden data-highlighted:bg-gray-100 dark:data-highlighted:bg-gray-800"
    >
      <span>${this.label}</span>${this.kbd
        ? html`<kbd class="text-xs font-mono text-gray-400 dark:text-gray-500">${this.kbd}</kbd>`
        : ''}
    </prosekit-autocomplete-item>`
  }
}

customElements.define('lit-editor-slash-menu-item', SlashMenuItemElement)

import 'prosekit/lit/autocomplete'

import { ContextConsumer } from '@lit/context'
import { html, LitElement } from 'lit'
import type { BasicExtension } from 'prosekit/basic'
import type { Editor } from 'prosekit/core'
import { canUseRegexLookbehind } from 'prosekit/core'

import { editorContext } from '../editor-context'

// Match inputs like "/", "/table", "/heading 1" etc. Do not match "/ heading".
const regex = canUseRegexLookbehind() ? /(?<!\S)\/(\S.*)?$/u : /\/(\S.*)?$/u

class SlashMenuElement extends LitElement {
  private editorConsumer = new ContextConsumer(this, {
    context: editorContext,
    subscribe: true,
  })

  override createRenderRoot() {
    return this
  }

  override render() {
    const editor = this.editorConsumer.value as Editor<BasicExtension> | undefined
    if (!editor) {
      return html``
    }

    return html`<prosekit-autocomplete-root .editor=${editor} .regex=${regex}>
      <prosekit-autocomplete-positioner class="block overflow-visible bg-transparent w-min h-min z-50 motion-safe:ease-out motion-safe:transition-transform motion-safe:duration-100">
        <prosekit-autocomplete-popup class="box-border data-[state=closed]:motion-safe:duration-150 motion-safe:transition-discrete motion-safe:transition-all data-[state=closed]:opacity-0 starting:opacity-0 opacity-100 data-[state=closed]:scale-95 starting:scale-95 scale-100 motion-safe:duration-40 rounded-lg border border-gray-200 dark:border-gray-800 bg-white dark:bg-gray-950 shadow-lg flex flex-col relative max-h-100 min-w-60 select-none overflow-auto whitespace-nowrap p-1">
          <lit-editor-slash-menu-item
            class="contents"
            label="Text"
            @select=${() => editor.commands.setParagraph()}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Heading 1"
            kbd="#"
            @select=${() => editor.commands.setHeading({ level: 1 })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Heading 2"
            kbd="##"
            @select=${() => editor.commands.setHeading({ level: 2 })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Heading 3"
            kbd="###"
            @select=${() => editor.commands.setHeading({ level: 3 })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Bullet list"
            kbd="-"
            @select=${() => editor.commands.wrapInList({ kind: 'bullet' })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Ordered list"
            kbd="1."
            @select=${() => editor.commands.wrapInList({ kind: 'ordered' })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Task list"
            kbd="[]"
            @select=${() => editor.commands.wrapInList({ kind: 'task' })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Toggle list"
            kbd=">>"
            @select=${() => editor.commands.wrapInList({ kind: 'toggle' })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Quote"
            kbd=">"
            @select=${() => editor.commands.setBlockquote()}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Table"
            @select=${() => editor.commands.insertTable({ row: 3, col: 3 })}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Divider"
            kbd="---"
            @select=${() => editor.commands.insertHorizontalRule()}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-item
            class="contents"
            label="Code"
            kbd="\`\`\`"
            @select=${() => editor.commands.setCodeBlock()}
          ></lit-editor-slash-menu-item>
          <lit-editor-slash-menu-empty class="contents"></lit-editor-slash-menu-empty>
        </prosekit-autocomplete-popup>
      </prosekit-autocomplete-positioner>
    </prosekit-autocomplete-root>`
  }
}

customElements.define('lit-editor-slash-menu', SlashMenuElement)
